INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["地","中","分"],"answer":"心","position":"suffix","explanation":"可組成:地心、中心、分心。","_meta":{"diversity":9,"commonness":9,"rationale":"地心(地球核心)、中心(中央)、分心(注意力分散)意義迥異且皆常用"},"definitions":{"地心":"地球的中心點。","中心":"與四周距離相等的位置；物體的正中央。;核心；事物的主體，最為重要的部分。;泛指某一占有樞紐地位的地點或機構。","分心":"分散心思、注意力。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["門","花","分"],"answer":"神","position":"suffix","explanation":"可組成:門神、花神、分神。","_meta":{"diversity":9,"commonness":9,"rationale":"門神=守護神、花神=司花女神、分神=分心,意義差異大"},"definitions":{"門神":"舊俗貼在門上的神像，用來驅鬼避邪，把守門戶。","花神":"掌管花卉的女神。也作「女夷」、「花姑」。;比喻善於種花的人。;花的精神。」","分神":"費心；費力。請人幫忙的客套話。;不專心；分散注意力。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["力","化","結"],"answer":"氣","position":"prefix","explanation":"可組成:氣力、氣化、氣結。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常見,氣意義從力量、變化、鬱結有別"},"definitions":{"氣力":"體力；力氣。;精力；功夫。","氣化":"物質從液態或固態轉變為氣態。也作「汽化」。;中醫指人體氣的運行變化和升降、出入、開闔等功能。","氣結":"鬱悶；憤怒。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["手","生","口"],"answer":"氣","position":"suffix","explanation":"可組成:手氣、生氣、口氣。","_meta":{"diversity":8,"commonness":9,"rationale":"手氣=運氣、生氣=發怒/有活力、口氣=語氣,意義差異大"},"definitions":{"手氣":"指賭博或摸彩時的運氣。","生氣":"因不合心意而氣惱。;生命的活力。","口氣":"口中散發出的氣味。;說話的措辭和語氣。也作「口吻」。;話中透露出來的含義。也作「口風」。;帶有地方特色的聲音或腔調。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["水","心","白"],"answer":"清","position":"prefix","explanation":"可組成:清水、清心、清白。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常見且意義有別"},"definitions":{"清水":"清澈透明的水；白水。;比喻物品或機構等清純潔淨。","清心":"形容心情恬靜，沒有牽掛和憂慮。;使清心。;中醫指清除心火。","清白":"清正純潔，沒有汙點。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","心","行"],"answer":"頭","position":"suffix","explanation":"可組成:人頭、心頭、行頭。","_meta":{"diversity":8,"commonness":8,"rationale":"人頭=人數、心頭=內心、行頭=裝扮,意義差異大"},"definitions":{"人頭":"人的頭。;人數。;臺⃝由於自願（賣、借）或非自願（詐騙），而提供個人資料作為不肖人士進行違法行為的代理人。;陸⃝人際關係。","心頭":"心上；心裡。","行頭":"傳統戲曲服裝的通稱；泛指服裝。;〈書〉古代軍隊行伍的隊長。;〈書〉行業的頭子，或傭役的總管。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["天","家","地"],"answer":"道","position":"suffix","explanation":"可組成:天道、家道、地道。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常見且道字意義不同"},"definitions":{"天道":"古代哲學術語：;(1)指自然界發展變化的客觀規律。;(2)指上帝意志的表現；吉凶禍福等徵兆。也作「天意」。;佛教術語。六道之一，指住於欲界、色界、無色界等三界的天人。;指氣候；天氣。;時間；時候。也作「天時」。","家道":"家中的經濟狀況。;家庭運道。;〈書〉治家的規範。","地道":"地底下開挖的坑道、隧道。;正宗的；純正的；符合標準的。也作「道地」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["大","道","生"],"answer":"理","position":"suffix","explanation":"可組成:大理、道理、生理。","_meta":{"diversity":8,"commonness":8,"rationale":"大理(地名)、道理、生理意義差異大"},"definitions":{"大理":"古國名（937－1253）。五代至宋，以白族為主體所建立的政權。轄境相當於今雲南全境、四川西南部等地，分設八府、四郡、三十七部。其王曾受宋封為雲南節度使、大理王。;職官名。春秋晉、齊、衛諸國皆置。主刑罰獄訟。秦、漢稱「廷尉」，漢景帝六年（1…","道理":"法則；規律。;根據；理由。;辦法；打算。","生理":"生物體的各種機能，即生物體及其各器官表現的生命活動。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["不","打","生"],"answer":"理","position":"suffix","explanation":"可組成:不理、打理、生理。","_meta":{"diversity":8,"commonness":10,"rationale":"不理(理睬)、打理(處理)、生理(生命機能)意義皆不同"},"definitions":{"不理":"不理會。;不處理。","打理":"整理；處理。;經營；管理。;臺⃝理睬。也作「搭理」、「答理」。陸⃝即「搭理」。","生理":"生物體的各種機能，即生物體及其各器官表現的生命活動。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","道","書"],"answer":"行","position":"prefix","explanation":"可組成:行人、行道、行書。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常見,行人(走路)、行道(街道/行業)、行書(字體)意義分歧"},"definitions":{"行人":"在路上行走的人。;〈書〉出征的人；行軍的人。","行道":"道路，供人或車、馬通行的帶狀地面。;實踐道德、道義、正道。;〈書〉走在道路上。","行書":"漢字字體之一。比草書工整，比楷書活潑。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["頭","道","家"],"answer":"行","position":"prefix","explanation":"可組成:行頭、行道、行家。","_meta":{"diversity":8,"commonness":8,"rationale":"行頭、行道、行家三詞常見且意義不同"},"definitions":{"行頭":"傳統戲曲服裝的通稱；泛指服裝。;〈書〉古代軍隊行伍的隊長。;〈書〉行業的頭子，或傭役的總管。","行道":"道路，供人或車、馬通行的帶狀地面。;實踐道德、道義、正道。;〈書〉走在道路上。","行家":"很內行的人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["事","口","學"],"answer":"業","position":"suffix","explanation":"可組成:事業、口業、學業。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常見,業義不同(事務、口造業、學習)"},"definitions":{"事業":"個人的理想或目標，用畢生精力去開創、經營而完成之，不達目標，絕不罷休。;臺⃝依各自不同之理念，從事有益社會大眾之單位或機構。;陸⃝特指沒有或僅有少量生產或經營收入，主要由國家經費開支的機構或單位。","口業":"佛教用語。指導致果報的言語，包括妄言、惡口、兩舌和綺語。;〈書〉唐宋人以詩文多綺語，故用以稱文學創作。;〈書〉賴以謀生的產業。","學業":"學習的課業。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["家","文","公"],"answer":"法","position":"suffix","explanation":"可組成:家法、文法、公法。","_meta":{"diversity":8,"commonness":8,"rationale":"家法、文法、公法分屬家庭、語言、法律,差異明顯"},"definitions":{"家法":"〈書〉古代師徒相承，自成一家的學術理論及治學方法。後泛指學術、文藝相傳的流派或風格。;治家的法規、準則。;指處罰家人的刑具。","文法":"語言的結構規則。;〈書〉文書法令。;〈書〉文章作法。","公法":"規定國家與人民間關係的法律。如憲法、行政法等。;規定國家與國家間關係的法律。如國際公法。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["調","報","理"],"answer":"情","position":"prefix","explanation":"可組成:情調、情報、情理。","_meta":{"diversity":8,"commonness":9,"rationale":"情調、情報、情理分屬氛圍、資訊、道理,語意差異大"},"definitions":{"情調":"情趣格調。","情報":"敵情的報告。引申為各種訊息和報告。","情理":"人的常情與事的常理。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","行","風"],"answer":"情","position":"suffix","explanation":"可組成:人情、行情、風情。","_meta":{"diversity":8,"commonness":9,"rationale":"人情、行情、風情皆常用且意義差異大"},"definitions":{"人情":"人在一般情況下的感情表現；做人處事應有的情理態度。;風俗；習性。;給人情面、方便。;人際間的饋贈或應酬。","行情":"商品、證券等的價格及利率、匯率等的情況。;身價。","風情":"風采；神情。;情懷；風雅的情趣。;風土人情。;有關風向、風力的情況。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["動","好","骨"],"answer":"感","position":"suffix","explanation":"可組成:動感、好感、骨感。","_meta":{"diversity":8,"commonness":9,"rationale":"動感、好感、骨感分別指動態、好印象、身材,差異大"},"definitions":{"動感":"藝術作品等給人活靈活現、栩栩如生的感覺。","好感":"（對人或事）滿意或喜愛的感覺。","骨感":"體形瘦削者給人瘦骨嶙峋的感覺。比喻多有缺陷。;身材瘦削者給人剛勁有力的感覺。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","法","火"],"answer":"文","position":"prefix","explanation":"可組成:文人、文法、文火。","_meta":{"diversity":8,"commonness":8,"rationale":"文人(人)、文法(語法)、文火(柔和)意義差異大"},"definitions":{"文人":"讀書人或從事文學研究、創作的人。","文法":"語言的結構規則。;〈書〉文書法令。;〈書〉文章作法。","文火":"（烹飪）微弱的火（與「武火」相對）。也作「微火」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["風","官","火"],"answer":"文","position":"prefix","explanation":"可組成:文風、文官、文火。","_meta":{"diversity":8,"commonness":8,"rationale":"文風文官文火涵蓋風格、官職、火候"},"definitions":{"文風":"文化的風氣。;文章的風格。","文官":"經國家考試及格，在政府機關中擔任文職工作的人員。","文火":"（烹飪）微弱的火（與「武火」相對）。也作「微火」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","中","分"],"answer":"文","position":"suffix","explanation":"可組成:上文、中文、分文。","_meta":{"diversity":8,"commonness":8,"rationale":"上文=前述、中文=語言、分文=錢,意涵差異大"},"definitions":{"上文":"文章或書籍中，某一文句、段落、章節之前的部分。也作「前文」。","中文":"我國的語言及文字；特指漢族的語言及文字。","分文":"極少的錢財。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","法","一"],"answer":"文","position":"suffix","explanation":"可組成:上文、法文、一文。","_meta":{"diversity":8,"commonness":8,"rationale":"上文=前述、法文=語言、一文=錢,差異明顯"},"definitions":{"上文":"文章或書籍中，某一文句、段落、章節之前的部分。也作「前文」。","法文":"用於記錄法國語言的文字；也指法國語言。;指法律的條文。","一文":"古時稱一枚銅幣。;一篇文章。;一條斑紋。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","氣","天"],"answer":"體","position":"suffix","explanation":"可組成:人體、氣體、天體。","_meta":{"diversity":8,"commonness":9,"rationale":"人體(身體)、氣體(物質狀態)、天體(天文物體)三義明顯不同"},"definitions":{"人體":"人的身體。","氣體":"沒有固定的形狀和體積，可以在空中或容器中自由流動的物質。如常溫下的空氣、氫氣、煤氣等。","天體":"天文物體的統稱。包括宇宙中各種星球、流星、宇宙塵等。;臺⃝指裸體。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["光","力","語"],"answer":"用","position":"prefix","explanation":"可組成:用光、用力、用語。","_meta":{"diversity":8,"commonness":8,"rationale":"用光耗盡、用力施力、用語措辭,差異大"},"definitions":{"用光":"用完了；用盡了。;攝影時採光的方法。有正面光、側光、逆光、頂光、腳光五種。","用力":"用力氣；使勁。","用語":"選用詞語；措辭。;選用的詞語。;特指具有專業特點或用途的詞語。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["情","外","方"],"answer":"形","position":"suffix","explanation":"可組成:情形、外形、方形。","_meta":{"diversity":8,"commonness":9,"rationale":"情形=狀況、外形=外觀、方形=形狀,三者意義差異明顯且常用"},"definitions":{"情形":"事物的實際狀況。","外形":"外在的形貌。","方形":"四個內角都是直角的四邊形。有正方形與長方形兩種。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["行","天","白"],"answer":"色","position":"suffix","explanation":"可組成:行色、天色、白色。","_meta":{"diversity":8,"commonness":9,"rationale":"行色(神情)、天色(光線)、白色(顏色),三種意義明確不同"},"definitions":{"行色":"出行時的神態、情景或氣派。","天色":"天空的顏色。可據以推測時間早晚或天氣變化的情況。","白色":"白顏色。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["一","出","國"],"answer":"色","position":"suffix","explanation":"可組成:一色、出色、國色。","_meta":{"diversity":8,"commonness":8,"rationale":"一色(同樣)、出色(優秀)、國色(絕美),意義差異明顯"},"definitions":{"一色":"相同的顏色。;全部一樣（不混雜其他的種類或樣式）。;一件。","出色":"傑出；出眾；超出一般。","國色":"一國之中容貌最為美豔的女子。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["學","色","言"],"answer":"聲","position":"prefix","explanation":"可組成:聲學、聲色、聲言。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常見,聲學為學科、聲色為神情、聲言為宣稱"},"definitions":{"聲學":"物理學的一個分支學科，研究聲波的產生、傳播、接收和效應等。按研究的方法、對象和頻率範圍，分為幾何聲學、物理聲學、分子聲學等等許多門類。","聲色":"（說話時的）聲音和表情。;〈書〉歌舞和美色。;陸⃝指生氣和活力。","聲言":"用語言、文字公開表示。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","名","相"],"answer":"聲","position":"suffix","explanation":"可組成:上聲、名聲、相聲。","_meta":{"diversity":9,"commonness":8,"rationale":"上聲聲調、名聲聲望、相聲曲藝,差異明顯"},"definitions":{"上聲":"漢語調類之一。古漢語四聲之一。;現代漢語四聲調中的第三聲，調值是214，注音符號的調號是「ˇ」。","名聲":"名氣；聲譽。","相聲":"一種曲藝，以「學、說、逗、唱」為主要藝術手段，幽默風趣，引人發笑。內容多為諷刺。有單口、對口、群口三種形式，多為對口（兩人表演）相聲。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["重","合","黃"],"answer":"金","position":"suffix","explanation":"可組成:重金、合金、黃金。","_meta":{"diversity":8,"commonness":9,"rationale":"重金、合金、黃金皆常見,意義各異"},"definitions":{"重金":"巨額錢款。","合金":"一種金屬元素與其他金屬或非金屬元素鎔合而成的物質。","黃金":"稀有、珍貴的金屬之一。質地軟、易延展，可打成金箔。色澤黃、抗腐蝕，黃金色澤歷久不變。熔點高、比重大，容易分辨。一般用來製造貨幣和裝飾品。通稱「金子」。;寶貴的；完美的。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["子","氣","下"],"answer":"天","position":"prefix","explanation":"可組成:天子、天氣、天下。","_meta":{"diversity":8,"commonness":9,"rationale":"天子=君王、天氣=氣象、天下=世界,皆常用且語意分散"},"definitions":{"天子":"帝王。古人認為帝王受命於天，為天之子，故稱。","天氣":"在一定時間和空間內大氣發生的各種氣象變化。;時候；時間。","天下":"古時指中國境內的全部；全國。;指全世界。;指國家或國家的統治權。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["一","老","明"],"answer":"天","position":"suffix","explanation":"可組成:一天、老天、明天。","_meta":{"diversity":8,"commonness":9,"rationale":"一天、老天、明天皆常用且天的意涵不同"},"definitions":{"一天":"整日；一個晝夜。;一個白天。;某一天。∥也作「一日」。","老天":"對主宰宇宙萬物的神的俗稱。;表示祈求或驚歎的用語。∥也作「老天爺」。","明天":"今天的下一天。;未來；不久的將來。∥也作「明日」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["方","主","力"],"answer":"地","position":"prefix","explanation":"可組成:地方、地主、地力。","_meta":{"diversity":8,"commonness":9,"rationale":"地方、地主、地力皆常見,意義差異大"},"definitions":{"地方":"中央政府以下各級行政區劃的統稱（與「中央」相對）。;本地；當地。;陸⃝指軍隊以外的部門。;區域。;處所；地點。;部位；位置。;部分。","地主":"住在本地的主人（對外來客人而言）。;土地所有人。;指僅靠出租土地過生活的人。","地力":"土地的肥沃程度及生產能力。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["道","家","生"],"answer":"人","position":"prefix","explanation":"可組成:人道、人家、人生。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞皆熟悉,人指道德/家戶/人生主體"},"definitions":{"人道":"尊重人類生命與價值，強調博愛、正義等道德理念與行為。;男女間的性行為。;指人類。佛教認為未解脫的眾生，會在六道（天、人、阿修羅、地獄、餓鬼、畜生）中不斷輪迴，人道為六道之一。也作「人間道」。;〈書〉人應遵循的道理、人倫。","人家":"指其他人。;指自己；我。;住戶。;家庭；家世。;女子的婆家、對象。","人生":"人存活在世上的生命、時間。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["生","事","口"],"answer":"人","position":"prefix","explanation":"可組成:人生、人事、人口。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞皆極常用,語意涵蓋人生/事務/人口"},"definitions":{"人生":"人存活在世上的生命、時間。","人事":"政府機關、公司行號中，有關人員升調、考核、獎懲、任免等業務。;世間的人、事、物。;人與人之間所發生的事情。;人情世故。;人力所能掌握的。;人的知覺、意識。","人口":"家中的人員數目。;在一定地區、時間內的所有合法居民。;泛指人。;人的嘴，特指人嘴所說的話。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["機","實","前"],"answer":"事","position":"prefix","explanation":"可組成:事機、事實、事前。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,事機(機會)、事實、事前語意各異"},"definitions":{"事機":"事情的機密。;行事的時機。","事實":"事情真實的情況。","事前":"事情發生或處理、了結以前。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["業","實","變"],"answer":"事","position":"prefix","explanation":"可組成:事業、事實、事變。","_meta":{"diversity":8,"commonness":9,"rationale":"事業、事實、事變皆常見且意義差異大"},"definitions":{"事業":"個人的理想或目標，用畢生精力去開創、經營而完成之，不達目標，絕不罷休。;臺⃝依各自不同之理念，從事有益社會大眾之單位或機構。;陸⃝特指沒有或僅有少量生產或經營收入，主要由國家經費開支的機構或單位。","事實":"事情真實的情況。","事變":"事物的變化。;突然發生的重大政治、軍事變故。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["生","法","公"],"answer":"事","position":"suffix","explanation":"可組成:生事、法事、公事。","_meta":{"diversity":8,"commonness":8,"rationale":"生事=惹事、法事=宗教儀式、公事=公務,差異顯著"},"definitions":{"生事":"惹事；招惹麻煩。","法事":"和尚、道士為祈福消災、超度亡魂等而舉行的儀式。","公事":"公家的事務。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["子","白","門"],"answer":"空","position":"prefix","explanation":"可組成:空子、空白、空門。","_meta":{"diversity":8,"commonness":8,"rationale":"空子漏洞、空白未填、空門佛門,語義差異大"},"definitions":{"空子":"〈口〉尚未被占盡的空間或時間。;可乘的機會或可利用的漏洞。","空白":"（書頁、版面、圖畫等上面）沒有圖文的部分；泛指某些沒有東西的地方。;空（ㄎㄨㄥˋkòng）著尚未利用的；沒有內容的。;沒有開發的領域、項目等。","空門":"佛門。佛教認為大千世界一切皆空，故稱。;足球等球類比賽中臨時無人防守的球門。;臺⃝家中無人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["地","中","名"],"answer":"空","position":"prefix","explanation":"可組成:空地、空中、空名。","_meta":{"diversity":8,"commonness":9,"rationale":"空地具體、空中方位、空名虛稱,語義差異佳"},"definitions":{"空地":"尚未利用的土地。;空著的尚未放東西的地方。","空中":"天空中；較高的空間。;指通過無線電信號傳播信息的。","空名":"虛名；與實際情況不符的名位。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["不","事","名"],"answer":"實","position":"suffix","explanation":"可組成:不實、事實、名實。","_meta":{"diversity":8,"commonness":8,"rationale":"不實、事實、名實皆常用,意義各異"},"definitions":{"不實":"不確實；不正確。","事實":"事情真實的情況。","名實":"名稱與實際情況；名聲與才幹、實際績效。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["言","正","主"],"answer":"真","position":"prefix","explanation":"可組成:真言、真正、真主。","_meta":{"diversity":8,"commonness":8,"rationale":"真言真正真主語意角色不同"},"definitions":{"真言":"真實無偽的言語。;宗教上指含有深奧教法的祕密語句。","真正":"名稱和實際相符的。;表示對某種情況的肯定，相當於「確實」、「的確」。","真主":"伊斯蘭教（回教）教徒所信仰、崇拜的唯一神。為創造萬物、無所不在的宇宙唯一主宰者。臺⃝也作「阿拉」。陸⃝也作「安拉」。（阿拉伯Allah）"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["手","名","日"],"answer":"假","position":"prefix","explanation":"可組成:假手、假名、假日。","_meta":{"diversity":9,"commonness":9,"rationale":"假手(借助)、假名、假日皆常用且意義差異明顯"},"definitions":{"假手":"假借他人的力量（以達到自己的目的）。;請他人代筆。","假名":"假借名義。;化名；虛假的名字。;日本文字所使用的字母，多借用漢字的偏旁。楷書稱為「片假名」，草書稱為「平假名」。;佛教用語。謂世界萬有及其差別，都由語言所安立，沒有真實的體性。","假日":"指休假、放假的日子。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["手","山","聲"],"answer":"假","position":"prefix","explanation":"可組成:假手、假山、假聲。","_meta":{"diversity":8,"commonness":8,"rationale":"假手、假山、假聲皆熟悉,意義有差異"},"definitions":{"假手":"假借他人的力量（以達到自己的目的）。;請他人代筆。","假山":"園林建築中，由人工造成，供人觀看、遊賞的小山。","假聲":"說話或歌唱時所使用的非自然的嗓音。京劇中的青衣、花旦、小生的唱唸多用假聲。也作「假嗓子」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["情","身","工"],"answer":"動","position":"prefix","explanation":"可組成:動情、動身、動工。","_meta":{"diversity":9,"commonness":9,"rationale":"動情、動身、動工三者意義差異大且都常用"},"definitions":{"動情":"產生愛慕、憐憫等感情。","動身":"啟程；出發。","動工":"（土木工程）開工或施工中。;開始工作或寫作。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["情","兵","力"],"answer":"動","position":"prefix","explanation":"可組成:動情、動兵、動力。","_meta":{"diversity":9,"commonness":8,"rationale":"動情情感、動兵軍事、動力力量,語意各異"},"definitions":{"動情":"產生愛慕、憐憫等感情。","動兵":"派出軍隊與敵方作戰。","動力":"使機械運作或物體運動的各種力量，如風力、水力、火力、原子能等均為動力的來源。;比喻促使事物進步、發展的助力。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["心","打","生"],"answer":"動","position":"suffix","explanation":"可組成:心動、打動、生動。","_meta":{"diversity":8,"commonness":9,"rationale":"心動(情感觸動)、打動(感動他人)、生動(活潑)三者意義各異"},"definitions":{"心動":"動心；產生想做某事的念頭。","打動":"用言語或行動讓人感動。","生動":"有生氣和活力的；能感動人的。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["開","出","流"],"answer":"動","position":"suffix","explanation":"可組成:開動、出動、流動。","_meta":{"diversity":8,"commonness":9,"rationale":"開動(啟動)、出動(派出)、流動(移動)三者語意分明"},"definitions":{"開動":"車輛、機器等開始運行。;臺⃝開始吃飯。;陸⃝（部隊）出發。","出動":"（許多人為某事）行動起來。;派出去從事某一行動。","流動":"（液體、氣體及某些聚集的顆粒）移動。;變動位置或改變狀態。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["房","自","香"],"answer":"暗","position":"prefix","explanation":"可組成:暗房、暗自、暗香。","_meta":{"diversity":9,"commonness":8,"rationale":"暗房場所、暗自副詞、暗香比喻,差異極大"},"definitions":{"暗房":"暗室；可調節成完全黑暗的房間。專用於處理對光敏感的感光材料，如底片、相紙等。","暗自":"私下；背地裡。","暗香":"形容若隱若現的香氣。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["道","地","流"],"answer":"暗","position":"prefix","explanation":"可組成:暗道、暗地、暗流。","_meta":{"diversity":8,"commonness":8,"rationale":"暗道、暗地、暗流三詞常見且語意層次分明"},"definitions":{"暗道":"祕密通道。;呢喃自語；暗自說道。","暗地":"暗中；私下。也作「暗地裡」。","暗流":"地面下或水面下的水流。;比喻潛伏的思想或動向。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["花","道","發"],"answer":"開","position":"prefix","explanation":"可組成:開花、開道、開發。","_meta":{"diversity":8,"commonness":9,"rationale":"開花=綻放、開道=引路、開發=發展,語意差異明顯"},"definitions":{"開花":"花朵綻放。;比喻像花朵那樣綻裂。;比喻十分高興，露出滿面笑容。;陸⃝比喻經驗傳開或事業發展、興盛。","開道":"開闢道路；在前面引路。","開發":"開採（資源等）。;開墾。;發現並利用；創制。;啟發；引導。;臺⃝發展。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["花","口","火"],"answer":"開","position":"prefix","explanation":"可組成:開花、開口、開火。","_meta":{"diversity":8,"commonness":10,"rationale":"開花、開口、開火三詞常用且意義各異"},"definitions":{"開花":"花朵綻放。;比喻像花朵那樣綻裂。;比喻十分高興，露出滿面笑容。;陸⃝比喻經驗傳開或事業發展、興盛。","開口":"張開嘴；借指說話、演唱、提出請求等。;打開缺口；出現裂縫。;開刃，把尚未使用的刀、剪等的刃口磨鋒利。","開火":"（交戰雙方）開始作戰。;比喻爭執或進行激烈爭鬥。∥也作「開戰」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["行","發","口"],"answer":"進","position":"prefix","explanation":"可組成:進行、進發、進口。","_meta":{"diversity":8,"commonness":8,"rationale":"進行抽象、進發出發、進口指入口或輸入,意義多元"},"definitions":{"進行":"向前行進；前進。;從事（某種持續性的活動）。","進發":"（車船、人員的集體）出發前進。","進口":"（船舶）駛進港口。;從外國把貨物運到本國。;建築物或場地的入口處。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["出","色","房"],"answer":"退","position":"prefix","explanation":"可組成:退出、退色、退房。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,退義各異"},"definitions":{"退出":"離開（某場所）；脫離（某個集體或某種活動）。;陸⃝退還。","退色":"（衣服、布料等）顏色逐漸變淺或脫落。;比喻本色、記憶等逐漸淡化或消失。∥也作「褪色」。","退房":"退租、搬離旅社。;取消原預訂的房間。;陸⃝退掉已經購買的房屋。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["火","兵","房"],"answer":"退","position":"prefix","explanation":"可組成:退火、退兵、退房。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,退義多元"},"definitions":{"退火":"中醫術語。指消除身體上有火的症狀，如口乾舌燥、自覺身體發熱感、小便量少色紅赤等。;一種金屬熱處理方法。將經過冷作加工的金屬材料加熱至特定溫度，並保持一段時間後，再緩緩冷卻，以降低其原先的硬度與殘留應力，可增加金屬的延展性，以利後續之成形加工…","退兵":"撤退軍隊。;使敵軍撤退；擊退敵兵。;指退敗的軍隊。","退房":"退租、搬離旅社。;取消原預訂的房間。;陸⃝退掉已經購買的房屋。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","門","花"],"answer":"生","position":"suffix","explanation":"可組成:人生、門生、花生。","_meta":{"diversity":8,"commonness":9,"rationale":"人生(生命)、門生(學生)、花生(植物),意義差異大"},"definitions":{"人生":"人存活在世上的生命、時間。","門生":"指跟從老師或前輩學習的學生。;科舉考試及第者對主考官的自稱。","花生":"植物名。一年生草本。羽狀複葉，開黃花。開花後子房在土中根部生長，發育成莢果。其莢果也叫花生，含有蛋白質及脂肪，可食，為主要油料作物之一。也作「落花生」、「長生果」。臺⃝俗稱「土豆」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["書","小","一"],"answer":"生","position":"suffix","explanation":"可組成:書生、小生、一生。","_meta":{"diversity":8,"commonness":9,"rationale":"書生(讀書人)、小生(角色)、一生(一輩子),意義各異"},"definitions":{"書生":"讀書人。","小生":"戲曲生角的一種。以扮演青年男子為主。可約分扇子生、紗帽生、翎子生、窮生等。;古時年輕讀書人的自謙辭。;指年輕人或後輩。","一生":"終生；一輩子。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","水","心"],"answer":"死","position":"prefix","explanation":"可組成:死人、死水、死心。","_meta":{"diversity":8,"commonness":9,"rationale":"死人指屍體、死水指停滯之水、死心指放棄念頭,三者語意差異大"},"definitions":{"死人":"死亡的人。;指人的屍體。","死水":"不流動的水。比喻長期停滯、沒有活力的地方。","死心":"打消一切念頭，不再抱任何希望。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["相","命","神"],"answer":"死","position":"prefix","explanation":"可組成:死相、死命、死神。","_meta":{"diversity":8,"commonness":8,"rationale":"死相罵人、死命拼命、死神角色,三者意義差異大"},"definitions":{"死相":"人死後的相貌。;形容心情沮喪呆滯的面孔。;令人討厭的模樣（多用於罵人或表示親暱）。","死命":"死亡的命運。;表示拼命地或拼死地（做事）。","死神":"神話中掌管人死亡的神；借指死亡。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["水","花","地"],"answer":"落","position":"prefix","explanation":"可組成:落水、落花、落地。","_meta":{"diversity":8,"commonness":8,"rationale":"落水、落花、落地皆常見,意義各異"},"definitions":{"落水":"掉入水中。比喻墮落。;做衣服之前，先將布料浸水。","落花":"凋落的花瓣。","落地":"（物體）落到地上。;指嬰兒生下來。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["年","意","路"],"answer":"來","position":"prefix","explanation":"可組成:來年、來意、來路。","_meta":{"diversity":8,"commonness":9,"rationale":"來年時間、來意意圖、來路出處,差異大"},"definitions":{"來年":"明年。","來意":"來這裡的意圖。","來路":"通向這裡的道路。;來源。;來歷。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["日","意","客"],"answer":"來","position":"prefix","explanation":"可組成:來日、來意、來客。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常見且意義分明"},"definitions":{"來日":"未來的日子；將來。","來意":"來這裡的意圖。","來客":"指來訪的客人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["道","文","名"],"answer":"正","position":"prefix","explanation":"可組成:正道、正文、正名。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常見,正字表正當、本文、本名,差異佳"},"definitions":{"正道":"正式修築和通行的道路。;比喻為人處事的正當途徑。∥也作「正路」。;正確的道理、準則。","正文":"指文章或著作的主體部分（不含序言、附注、附錄等）。","正名":"透過辨正，給予合適的名稱或名分，使名實相符。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["子","然","道"],"answer":"公","position":"prefix","explanation":"可組成:公子、公然、公道。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,公分別表貴族、公開、公平"},"definitions":{"公子":"世家豪門子弟的通稱。;對他人兒子的敬稱。;尊稱年輕男子。;〈書〉諸侯之子。","公然":"當眾公開地；無所顧忌地。","公道":"公正的道理。;公平；合理。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["法","房","自"],"answer":"私","position":"prefix","explanation":"可組成:私法、私房、私自。","_meta":{"diversity":8,"commonness":8,"rationale":"私法私房私自詞性語意皆不同"},"definitions":{"私法":"指有關保護私人利益的法律。如民法、商法、婚姻法等。","私房":"私人所有的房屋。;家庭成員個人私下積蓄的錢財。也作「私蓄」。;不讓別人知道的。","私自":"私下；自己做主。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["文","出","明"],"answer":"言","position":"suffix","explanation":"可組成:文言、出言、明言。","_meta":{"diversity":8,"commonness":8,"rationale":"文言指文體、出言指說話、明言指明白說,差異大"},"definitions":{"文言":"以古漢語為基礎的書面語（與「白話」相對）。","出言":"說出話語。也作「出語」。","明言":"坦白說出。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["名","出","流"],"answer":"言","position":"suffix","explanation":"可組成:名言、出言、流言。","_meta":{"diversity":8,"commonness":8,"rationale":"名言、出言、流言皆常用且意義各異"},"definitions":{"名言":"著名的話。","出言":"說出話語。也作「出語」。","流言":"到處流傳的毫無根據的話。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["不","中","分"],"answer":"外","position":"suffix","explanation":"可組成:不外、中外、分外。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞皆常用,外字語意有別(除此之外/內外/格外)"},"definitions":{"不外":"不超出某個範圍之外。也作「不外乎」。","中外":"中國和外國的合稱。","分外":"職責或義務範疇以外。;格外；特別。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["流","三","神"],"answer":"通","position":"suffix","explanation":"可組成:流通、三通、神通。","_meta":{"diversity":8,"commonness":8,"rationale":"流通=流動、三通=三項通、神通=能力,語意多元"},"definitions":{"流通":"流動暢通；不滯塞。;指商品、貨幣流動周轉。","三通":"唐代杜佑《通典》、宋代鄭樵《通志》、元代馬端臨《文獻通考》三部國學書籍的合稱。;指自1988年以來，海峽兩岸陸續直接通郵、通商、通航的合稱。","神通":"佛教指無所不能的法力。借指特別高超的本領。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["流","清","交"],"answer":"通","position":"suffix","explanation":"可組成:流通、清通、交通。","_meta":{"diversity":8,"commonness":9,"rationale":"流通、清通、交通皆常見且意義有別"},"definitions":{"流通":"流動暢通；不滯塞。;指商品、貨幣流動周轉。","清通":"（文章）層次清楚，文句通順。;〈書〉清明通達。","交通":"透過陸、海、空等運輸工具以進行人員、貨物的流通與交換，亦指信函、電信等資訊方面的往來。;交互流通。;〈書〉結交；勾結。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["明","轉","直"],"answer":"達","position":"suffix","explanation":"可組成:明達、轉達、直達。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常見,意義各異"},"definitions":{"明達":"認識透徹，通達事理。","轉達":"把一方的意思轉告給另一方。","直達":"中途不轉換交通工具或不加停留而直接到達目的地。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["通","和","歸"],"answer":"順","position":"suffix","explanation":"可組成:通順、和順、歸順。","_meta":{"diversity":8,"commonness":8,"rationale":"通順=流暢、和順=溫和、歸順=投降,意義多元"},"definitions":{"通順":"通達順暢；沒有扞格。","和順":"柔和平順。","歸順":"歸附順從。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["手","官","中"],"answer":"高","position":"prefix","explanation":"可組成:高手、高官、高中。","_meta":{"diversity":8,"commonness":9,"rationale":"高手、高官、高中皆常見且意義不同"},"definitions":{"高手":"能力、本領特別強的人。","高官":"高級官員。","高中":"高級中學的簡稱：;臺⃝介於國民中學與大專院校之間的學校。以培養學生研究高深學術及學習專門知識的基本能力，奠定其接受高等教育的基礎。;陸⃝實施普通中等教育後一階段教育的學校。;高分通過考試。多用於祝賀人通過考試。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["頭","地","落"],"answer":"低","position":"prefix","explanation":"可組成:低頭、低地、低落。","_meta":{"diversity":8,"commonness":9,"rationale":"低頭(動作)、低地(地形)、低落(情緒)三義分明"},"definitions":{"低頭":"垂下頭。;屈服。","低地":"地勢較低處。","低落":"很快下降。;不振作；不旺盛。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["長","情","重"],"answer":"深","position":"prefix","explanation":"可組成:深長、深情、深重。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常用且深各表程度、情感、嚴重"},"definitions":{"深長":"又深又長。;意義深刻，耐人尋味。","深情":"深厚的感情。;感情深厚。","深重":"形容程度深而嚴重。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["景","加","幽"],"answer":"深","position":"suffix","explanation":"可組成:景深、加深、幽深。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常用,意義差異明顯"},"definitions":{"景深":"指錄影或攝影時，可使主體景物前後的景象成像清晰的範圍。","加深":"增加深度或程度。","幽深":"幽靜深邃。;幽暗深邃。∥也作「深幽」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["風","生","重"],"answer":"輕","position":"prefix","explanation":"可組成:輕風、輕生、輕重。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常見,輕風自然、輕生比喻、輕重抽象"},"definitions":{"輕風":"輕柔的微風；氣象學上指2級風。","輕生":"不珍惜生命（多指自殺）。","輕重":"重量的大小；用力的大小。;指說話的分寸。;（事情的）主次；（程度的）深淺。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["火","情","學"],"answer":"熱","position":"prefix","explanation":"可組成:熱火、熱情、熱學。","_meta":{"diversity":8,"commonness":8,"rationale":"熱火(熱烈)、熱情(情感)、熱學(學科)語意分歧"},"definitions":{"熱火":"熱烈。;情誼親密；親熱的樣子。;熱烘烘的樣子。;熾熱的火焰；用以比喻激情。","熱情":"熱烈的感情。;感情熱烈。","熱學":"物理學中研究熱現象的規律及其應用的學科。包括量熱學、測溫學、熱膨脹、熱傳遞等內容。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["水","氣","門"],"answer":"冷","position":"prefix","explanation":"可組成:冷水、冷氣、冷門。","_meta":{"diversity":8,"commonness":9,"rationale":"皆常用,冷水實物、冷氣設備、冷門比喻意義多元"},"definitions":{"冷水":"生水；未煮沸的涼水。;冷開水；溫度較低的水。","冷氣":"寒冷的氣流。;用來降低室內溫度的電器。也作「冷氣機」。","冷門":"冷清而乏人進出的門庭。比喻不受重視、不合時興的事物（與「熱門」相對）。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["玉","性","好"],"answer":"剛","position":"prefix","explanation":"可組成:剛玉、剛性、剛好。","_meta":{"diversity":8,"commonness":8,"rationale":"剛玉礦物、剛性物理、剛好副詞,語義差異大"},"definitions":{"剛玉":"礦物。主要成分是三氧化二鋁，有玻璃光澤，硬度僅次於金剛石。紅色透明的叫紅寶石，其他透明的顏色叫藍寶石。是貴重的裝飾品，亦可做精密儀器的軸承。也作「剛石」。","剛性":"（物體）剛硬而不易變形的性質（與「柔性」相對）。;剛強的氣質或性格。;不易改變或變通的。","剛好":"正合適。;正巧；恰巧。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["從","優","溫"],"answer":"良","position":"suffix","explanation":"可組成:從良、優良、溫良。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常用,從良意義與優良、溫良差異明顯"},"definitions":{"從良":"妓女脫離原來的生活而嫁人。;奴婢因役滿或贖身而獲得自由。","優良":"優秀良好。","溫良":"溫和善良。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["白","花","光"],"answer":"眼","position":"prefix","explanation":"可組成:眼白、眼花、眼光。","_meta":{"diversity":8,"commonness":8,"rationale":"眼白生理、眼花狀態、眼光抽象,差異佳"},"definitions":{"眼白":"眼球最外層的纖維膜，白色而不透明，具有保護眼球內部組織、維持眼球形態等功用。也作「白眼珠」、「白眼球」、「鞏膜」。;〈書〉眼睛朝上或向旁邊看，顯出白眼珠，表示對人藐視或厭惡。也作「白眼」。","眼花":"眼睛昏花，看東西模糊不清。","眼光":"視線。;觀察鑒別事物的能力；眼力。;觀點；看法。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["下","生","光"],"answer":"眼","position":"prefix","explanation":"可組成:眼下、眼生、眼光。","_meta":{"diversity":8,"commonness":8,"rationale":"眼下時間、眼生陌生、眼光見識,差異明顯"},"definitions":{"眼下":"目前。","眼生":"看起來有陌生感。","眼光":"視線。;觀察鑒別事物的能力；眼力。;觀點；看法。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","名","出"],"answer":"手","position":"suffix","explanation":"可組成:上手、名手、出手。","_meta":{"diversity":8,"commonness":8,"rationale":"上手(熟練)、名手(高手)、出手(動作)意義各異"},"definitions":{"上手":"到手，指達到某種目的。;操作；動手。;著手。;位置較尊的一側。也作「上首」。","名手":"以技藝精湛而著名的人；名家。","出手":"脫手；賣出。;拿出；用錢。;動手；展開行動。;展現出的本領。;京劇中武打的技巧。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["分","一","出"],"answer":"手","position":"suffix","explanation":"可組成:分手、一手、出手。","_meta":{"diversity":8,"commonness":9,"rationale":"分手(離別)、一手(獨自)、出手(動作)皆常用且義異"},"definitions":{"分手":"分開；離別。;結束戀人關係。","一手":"一隻手（前後兩句使用，表示同時進行兩件事）。;掌握的技藝或本領。;表示單獨或獨自地。;一種手段；不正當的方法。;滿手。","出手":"脫手；賣出。;拿出；用錢。;動手；展開行動。;展現出的本領。;京劇中武打的技巧。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["頭","書","上"],"answer":"香","position":"suffix","explanation":"可組成:頭香、書香、上香。","_meta":{"diversity":8,"commonness":9,"rationale":"頭香、書香(讀書氛圍)、上香(動作)語法與意義皆異"},"definitions":{"頭香":"開春或慶典，到寺廟最先插上第一炷香，以討吉利。也多用於搶到首位。;臺⃝網路用語。指第一篇貼上的文章或是某篇文章的第一個回覆、推文。","書香":"原指為防止書籍被蟲蛀而放置的香料，後借指讀書的人家或風氣。","上香":"燒香致祭。也作「行香」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["人","上","小"],"answer":"品","position":"suffix","explanation":"可組成:人品、上品、小品。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常見,品德、等級、文體三義"},"definitions":{"人品":"人的品行、人格。;人的相貌、儀容。","上品":"上等的品質、品級；上等的物品。;魏晉九品中正制上等品第的士族。","小品":"指短評、雜文或其他形式短小的文學作品，筆致生動活潑。;指角色少、劇情簡單活潑、形式短小的戲劇作品。;指七卷本的《小品般若波羅蜜經》。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["風","門","道"],"answer":"家","position":"prefix","explanation":"可組成:家風、家門、家道。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞皆常用且家的意涵略有差異"},"definitions":{"家風":"家族世代相承的風氣或傳統。","家門":"住家大門；借指自己的家。;家庭；家族。;門第；家族的名聲。;指個人的家世、經歷等。","家道":"家中的經濟狀況。;家庭運道。;〈書〉治家的規範。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["書","小","法"],"answer":"家","position":"prefix","explanation":"可組成:家書、家小、家法。","_meta":{"diversity":8,"commonness":8,"rationale":"皆為常見詞,家的指涉各異"},"definitions":{"家書":"家人間往來的書信。也作「家信」。","家小":"指妻子及兒女。;特指妻子。","家法":"〈書〉古代師徒相承，自成一家的學術理論及治學方法。後泛指學術、文藝相傳的流派或風格。;治家的法規、準則。;指處罰家人的刑具。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["國","正","命"],"answer":"中","position":"suffix","explanation":"可組成:國中、正中、命中。","_meta":{"diversity":8,"commonness":8,"rationale":"國中=學校、正中=正當中、命中=擊中,三義皆不同"},"definitions":{"國中":"國民中學的簡稱。國民義務教育的第二階段學校。年滿12歲的少年都須入學，修業時間為3年。","正中":"中心位置。也作「正當中」。","命中":"射中；擊中；投中。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","車","學"],"answer":"位","position":"suffix","explanation":"可組成:上位、車位、學位。","_meta":{"diversity":9,"commonness":9,"rationale":"三詞極常見,語義差異極大"},"definitions":{"上位":"位置在上；高位。;上座；貴客座位。","車位":"供汽車停放的位置，一個車位停放一輛汽車。也作「停車位」。","學位":"指大學以上學生，修畢學分後，經過評定，認可其具備某種專業知識的程度，所授予的學術資格。一般分學士、碩士、博士三種。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["上","本","方"],"answer":"位","position":"suffix","explanation":"可組成:上位、本位、方位。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常見,語義差異明顯"},"definitions":{"上位":"位置在上；高位。;上座；貴客座位。","本位":"貨幣制度的基本單位，或貨幣價值的計算標準。;自己所在的單位、崗位。","方位":"方向。東、西、南、北為基本方位，東北、東南、西北、西南為中間方位。;方向和位置。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["國","成","對"],"answer":"立","position":"suffix","explanation":"可組成:國立、成立、對立。","_meta":{"diversity":8,"commonness":9,"rationale":"國立=設立、成立=構成、對立=相對,意義多元且常用"},"definitions":{"國立":"由國家所設立的。","成立":"（組織或機構）正式建立。;論點或假設有根據，站得住腳。;案件經過法定程序，正式成為議案或提案。","對立":"相對而立。;互相排斥；相互敵對。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["玉","對","起"],"answer":"立","position":"suffix","explanation":"可組成:玉立、對立、起立。","_meta":{"diversity":8,"commonness":8,"rationale":"玉立、對立、起立意義差異大且常見"},"definitions":{"玉立":"形容身材修長或形體挺拔，立姿優美。;〈書〉比喻節操堅定不變。","對立":"相對而立。;互相排斥；相互敵對。","起立":"站起來（多用作口令）。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["文","開","老"],"answer":"化","position":"suffix","explanation":"可組成:文化、開化、老化。","_meta":{"diversity":8,"commonness":9,"rationale":"文化、開化、老化皆常用且語意不同"},"definitions":{"文化":"指人類在歷史發展過程中，創造的物質財富和精神財富的總成果。;指運用文字及知識的能力。;指某一領域或某一範疇體現的思想、觀念、道德、行為規範以及風俗習慣等。;考古學上指同一歷史時期所呈現的遺蹟、遺物的綜合體。如建築形式、使用工具、器物、材料、…","開化":"指人類由原始狀態進入文明狀態。;思想開明，不保守。;陸⃝江河、大地等開始解凍。也作「開凍」。","老化":"人或動物的生理隨年歲增長而機能衰退。;人口結構中老年人比例變大。;物體或事物變得陳舊、過時。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["火","兒","老"],"answer":"化","position":"suffix","explanation":"可組成:火化、兒化、老化。","_meta":{"diversity":8,"commonness":8,"rationale":"火化、兒化、老化三詞語法意義皆不同"},"definitions":{"火化":"焚燒遺體。","兒化":"現代漢語中的一種語音現象。即後綴「兒」字不自成音節，而是和前面的音節合讀而成為一個詞。如「花兒」不讀作ㄏㄨㄚㄦˊhuā’ér（兩個音節），而讀作ㄏㄨㄚㄦhuār（一個音節）。","老化":"人或動物的生理隨年歲增長而機能衰退。;人口結構中老年人比例變大。;物體或事物變得陳舊、過時。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["法","眼","三"],"answer":"界","position":"suffix","explanation":"可組成:法界、眼界、三界。","_meta":{"diversity":9,"commonness":8,"rationale":"法界、眼界、三界三種界含義不同"},"definitions":{"法界":"大乘佛教意謂諸法的根源，即全宇宙的存在。根源不外是真理本身，因此法界與空性、真如、實際同義。;佛教將一切存在分成十八類，即「六根」（眼、耳、鼻、舌、身、意）、「六塵」（色、聲、香、味、觸、法）、「六識」（眼識、耳識、鼻識、舌識、身識、意識）…","眼界":"目光所涉及的範圍。借指知識、見聞的廣度。","三界":"佛教用語。指世俗眾生存在的三種狀態與境界：欲界（具有食欲、淫欲等欲望）、色界（欲界之上，已離食、淫二欲，而仍具有色質）、無色界（色界之上，只有受、想、行、識四種心理活動，而無物質）。佛教認為三界都屬於「迷界」；所以從中解脫，進入涅槃，才是修…"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'middle', '{"hints":["子","行","手"],"answer":"分","position":"prefix","explanation":"可組成:分子、分行、分手。","_meta":{"diversity":8,"commonness":9,"rationale":"分子、分行(銀行單位)、分手(離別),語意角色差異明顯"},"definitions":{"分子":"分數或分式中，寫在橫線（或斜線）上方的數或式子。如1／5中的1，或（x-2）／（3x-8）中的x-2。;能夠獨立存在、並且保持物質一切化學性質的最小顆粒的物質。由原子組成。;構成某個群體的個體；具有某些特徵的人。;集體送禮或支出款項時，每個…","分行":"銀行或商行的分支機構。","分手":"分開；離別。;結束戀人關係。"}}');
